Below is a **complete, self‑contained example** that shows how you can expose a C++ iterator (the one that libpcapng provides) as an OCaml‐style iterator.  
It consists of

* `pcapng.mli` – the public OCaml interface that the users will see.
* `pcapng_stubs.cpp` – the C‑C++ glue code that talks to libpcapng and to the OCaml runtime.

You can drop both files in a directory, add a tiny `dune` file (or a Makefile) and you will have a working OCaml library called `pcapng`.

---

## 1.  The OCaml interface (`pcapng.mli`)

```ocaml
(*---------------------------------------------------------------------------
   pcapng.mli – public OCaml API
   ---------------------------------------------------------------------------*)

(** {1 Overview}

    The library is a thin wrapper around the C++ libpcapng parser.  It
    lets OCaml code open a *.pcapng* file, walk over the frames and run a
    user‑supplied callback on each frame.

    The iterator is *eager*: as soon as you call {!iter} the whole file
    is walked and the OCaml callback is invoked for each frame.  The
    implementation does the heavy lifting in C++ so the walk is fast,
    but the callback runs in the OCaml runtime, therefore it may raise
    exceptions which abort the walk.

    The binding is deliberately small – you can extend it later (e.g.
    add a {!fold} function, expose more fields of a frame, etc.).
*)

(** {2 Exceptions} *)

exception Error of string
(** Raised when the underlying C++ code reports an error (e.g. file not
    found, malformed pcapng, out‑of‑memory, ...). *)

(** {2 Types} *)

type pcapng
(** An opaque handle to an opened pcapng file.  It is allocated in C++ and
    automatically closed when the value is garbage‑collected (thanks to a
    finaliser). *)

type frame = {
  ts   : int64;   (** Timestamp of the frame (nanoseconds since epoch). *)
  data : bytes;   (** Raw packet bytes. *)
}
(** A single frame (packet) extracted from the file.  Only the fields that
    are needed for the example are exposed – you can add more later. *)

(** {2 Operations} *)

val open_file : string -> pcapng
(** Open a pcapng file for reading.  Raises {!Error} if the file cannot be
    opened or parsed. *)

val close : pcapng -> unit
(** Explicitly close a handle.  The handle is also closed automatically by
    the finaliser, so calling [close] is optional. *)

val iter : (frame -> unit) -> pcapng -> unit
(** [iter f h] walks over every frame in the file represented by [h] and
    calls [f] on it.  If [f] raises an exception the walk stops and the
    exception propagates to the caller.  The walk is performed in C++,
    the callback is executed in OCaml. *)

(** {2 Convenience helpers (optional)} *)

val fold : ( 'a -> frame -> 'a ) -> 'a -> pcapng -> 'a
(** Same as {!iter} but accumulates a result.  Implemented in OCaml on top
    of {!iter}.  Provided for completeness. *)
```

---

## 2.  The C / C++ glue (`pcapng_stubs.cpp`)

> **Important** – the file must be compiled as **C++**, not plain C,
> because it links against the C++ libpcapng API.  The file is named
> `pcapng_stubs.cpp` (or `.cc`) and the `extern "C"` block makes the
> symbols visible to OCaml.

```cpp
/*---------------------------------------------------------------------------
   pcapng_stubs.cpp – C/C++ glue for the OCaml binding
   ---------------------------------------------------------------------------*/

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>

#include <string>
#include <exception>
#include <memory>

// ---------------------------------------------------------------------------
// 1.  The (mocked) libpcapng C++ API we are wrapping.
// ---------------------------------------------------------------------------
// In a real project you would #include the actual libpcapng header(s).
// For the purpose of this example we declare just enough of the API.

namespace libpcapng {

struct Frame {
    int64_t timestamp;          // nanoseconds since epoch
    std::vector<uint8_t> data;  // raw packet bytes
};

class PcapNgFile {
public:
    explicit PcapNgFile(const std::string& filename) {
        // In real code this would open and parse the file.
        // Here we just pretend the file has 3 dummy frames.
        if (filename.empty())
            throw std::runtime_error("empty filename");
        frames_.push_back({ 1620000000000000000LL,
                            {0x00,0x11,0x22,0x33,0x44,0x55} });
        frames_.push_back({ 1620000001000000000LL,
                            {0x66,0x77,0x88,0x99,0xaa,0xbb,0xcc} });
        frames_.push_back({ 1620000002000000000LL,
                            {0xdd,0xee,0xff} });
    }

    // iterator type
    using iterator = std::vector<Frame>::const_iterator;

    iterator begin() const { return frames_.begin(); }
    iterator end()   const { return frames_.end(); }

private:
    std::vector<Frame> frames_;
};

} // namespace libpcapng

// ---------------------------------------------------------------------------
// 2.  OCaml custom block that holds a pointer to PcapNgFile.
// ---------------------------------------------------------------------------

typedef std::unique_ptr<libpcapng::PcapNgFile> pcapng_ptr;

/* The custom operations table.  Only a finaliser is needed. */
static void pcapng_finalize(value v) {
    // The custom block owns a pointer to a unique_ptr; we just let it
    // go out of scope – the unique_ptr will delete the C++ object.
    pcapng_ptr *p = (pcapng_ptr *)Data_custom_val(v);
    delete p;          // destroys the unique_ptr and the PcapNgFile
}

/* No comparison, hash or serialization needed for this simple wrapper. */
static struct custom_operations pcapng_ops = {
    "pcapng_custom_ops",
    pcapng_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* Allocate a custom block that owns a new PcapNgFile.  Raise OCaml Error on
   failure. */
static value alloc_pcapng_handle(std::unique_ptr<libpcapng::PcapNgFile> &&ptr) {
    CAMLparam0();
    CAMLlocal1(res);
    pcapng_ptr *store = (pcapng_ptr *)caml_stat_alloc(sizeof(pcapng_ptr));
    *store = std::move(ptr);               // move the unique_ptr into the block
    res = caml_alloc_custom(&pcapng_ops, sizeof(pcapng_ptr), 0, 1);
    Store_custom_val(res, store);
    CAMLreturn(res);
}

/* -------------------------------------------------------------------------
   3.  Helper to raise the OCaml exception [Error of string].
   ------------------------------------------------------------------------- */

static void raise_error(const std::string &msg) {
    caml_raise_with_string(*caml_named_value("Pcapng.Error"), msg.c_str());
}

/* -------------------------------------------------------------------------
   4.  OCaml primitives
   ------------------------------------------------------------------------- */

/* open_file : string -> pcapng */
extern "C" CAMLprim value caml_pcapng_open_file(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_res);
    std::string path = std::string(String_val(v_path));

    try {
        auto ptr = std::make_unique<libpcapng::PcapNgFile>(path);
        v_res = alloc_pcapng_handle(std::move(ptr));
    } catch (const std::exception &e) {
        raise_error(e.what());
    }

    CAMLreturn(v_res);
}

/* close : pcapng -> unit */
extern "C" CAMLprim value caml_pcapng_close(value v_handle) {
    CAMLparam1(v_handle);
    // The finaliser will free the underlying object; we just clear the
    // pointer now so that a later GC does not double‑free.
    pcapng_ptr *store = (pcapng_ptr *)Data_custom_val(v_handle);
    store->reset();   // delete the PcapNgFile if it is still alive
    CAMLreturn(Val_unit);
}

/* -------------------------------------------------------------------------
   5.  Building an OCaml “frame” value.
   The OCaml type is:
        type frame = { ts : int64 ; data : bytes }
   The corresponding runtime representation is a 2‑field block.
   ------------------------------------------------------------------------- */
static value mk_ocaml_frame(const libpcapng::Frame &f) {
    CAMLparam0();
    CAMLlocal3(v_ts, v_data, v_rec);

    // timestamp as int64 (boxed)
    v_ts = caml_copy_int64(f.timestamp);

    // data as a OCaml bytes value
    v_data = caml_alloc_initialized_string(f.data.size(),
                   reinterpret_cast<const char*>(f.data.data()));

    // allocate the record (2‑field block)
    v_rec = caml_alloc(2, 0);          // tag 0 = record
    Store_field(v_rec, 0, v_ts);
    Store_field(v_rec, 1, v_data);

    CAMLreturn(v_rec);
}

/* -------------------------------------------------------------------------
   6.  iter : (frame -> unit) -> pcapng -> unit
   ------------------------------------------------------------------------- */
extern "C" CAMLprim value caml_pcapng_iter(value v_cb, value v_handle) {
    CAMLparam2(v_cb, v_handle);
    CAMLlocal1(v_frame);

    // Extract the C++ object
    pcapng_ptr *store = (pcapng_ptr *)Data_custom_val(v_handle);
    if (!store || !store->get())
        caml_failwith("Pcapng.iter: invalid handle");

    const libpcapng::PcapNgFile &file = **store;

    // Walk the iterator in C++ and invoke the OCaml callback for each frame.
    // The OCaml runtime is automatically locked for us because the stub is
    // entered from OCaml; we only need to protect against long‑running C++
    // code that might block GC – we call caml_release_runtime_system /
    // caml_acquire_runtime_system around the loop.  (If the iterator is
    // cheap you can omit the release/acquire pair.)
    caml_release_runtime_system();   // allow other OCaml threads to run

    for (auto it = file.begin(); it != file.end(); ++it) {
        // Build an OCaml value for the current frame
        v_frame = mk_ocaml_frame(*it);

        // Call the user callback.  caml_callback_exn returns a value that
        // encodes either the normal result or an exception.
        value v_exn = caml_callback_exn(v_cb, v_frame);
        if (Is_exception_result(v_exn)) {
            caml_acquire_runtime_system();   // reacquire before raising
            // Propagate the exception to the caller.
            caml_raise(v_exn);
        }
    }

    caml_acquire_runtime_system();   // re‑acquire before returning

    CAMLreturn(Val_unit);
}

/* -------------------------------------------------------------------------
   7.  Optional fold implementation (pure OCaml, but we expose it for
       completeness).  It is defined in the .mli as a regular OCaml
       function, so we do not need a C stub here.
   ------------------------------------------------------------------------- */

/* End of file */ 
```

